import heapq

def solve(grid: list[list[int]], k: int) -> int:
    m, n = len(grid), len(grid[0])
    # Directions for normal moves: right and down
    directions = [(0, 1), (1, 0)]

    # Priority queue: (total_cost, i, j, remaining_k)
    heap = []
    heapq.heappush(heap, (0, 0, 0, k))

    # Visited dictionary: key is (i, j, remaining_k), value is the minimal cost to reach here
    visited = {}
    visited[(0, 0, k)] = 0

    while heap:
        current_cost, i, j, remaining_k = heapq.heappop(heap)
        if i == m - 1 and j == n - 1:
            return current_cost

        if visited.get((i, j, remaining_k), float('inf')) < current_cost:
            continue

        # Normal moves
        for di, dj in directions:
            ni, nj = i + di, j + dj
            if 0 <= ni < m and 0 <= nj < n:
                new_cost = current_cost + grid[ni][nj]
                if new_cost < visited.get((ni, nj, remaining_k), float('inf')):
                    visited[(ni, nj, remaining_k)] = new_cost
                    heapq.heappush(heap, (new_cost, ni, nj, remaining_k))

        # Teleport moves
        if remaining_k > 0:
            for x in range(m):
                for y in range(n):
                    if (x != i or y != j) and grid[x][y] <= grid[i][j]:
                        new_cost = current_cost
                        if new_cost < visited.get((x, y, remaining_k - 1), float('inf')):
                            visited[(x, y, remaining_k - 1)] = new_cost
                            heapq.heappush(heap, (new_cost, x, y, remaining_k - 1))

    return -1  # Should not reach here if the grid is valid
